import{_ as d,E as t,o as i,c,J as a,V as e}from"./chunks/framework.bQWQ8j9j.js";const u=JSON.parse('{"title":"box-sizing","description":"","frontmatter":{},"headers":[],"relativePath":"cheat-sheets/css/box-sizing.md","filePath":"cheat-sheets/css/box-sizing.md","lastUpdated":1692694385000}'),r={name:"cheat-sheets/css/box-sizing.md"},n=e('<h1 id="box-sizing" tabindex="-1">box-sizing <a class="header-anchor" href="#box-sizing" aria-label="Permalink to &quot;box-sizing&quot;">​</a></h1><h2 id="box-sizing-是什么" tabindex="-1">box-sizing 是什么 <a class="header-anchor" href="#box-sizing-是什么" aria-label="Permalink to &quot;box-sizing 是什么&quot;">​</a></h2><p><code>box-sizing</code> 用于设置如何计算元素总宽高。</p><h2 id="box-sizing-的取值与含义" tabindex="-1">box-sizing 的取值与含义 <a class="header-anchor" href="#box-sizing-的取值与含义" aria-label="Permalink to &quot;box-sizing 的取值与含义&quot;">​</a></h2><p><code>box-sizing</code> 的常见取值有 <code>content-box</code>（默认值）和 <code>border-box</code>。</p><h3 id="content-box" tabindex="-1">content-box <a class="header-anchor" href="#content-box" aria-label="Permalink to &quot;content-box&quot;">​</a></h3><p>设置为 <code>content-box</code> 时，元素 <code>width</code>、<code>height</code> 分别表示元素内容 content 宽高，<code>padding</code>、<code>border-width</code> 设置的值另外计算。</p><h3 id="border-box" tabindex="-1">border-box <a class="header-anchor" href="#border-box" aria-label="Permalink to &quot;border-box&quot;">​</a></h3><p>设置为 <code>border-box</code> 时，元素 <code>width</code>、<code>height</code> 分别表示元素内容 content、<code>padding</code>、<code>border-width</code> 对应值之和。</p><h2 id="理解-border-box" tabindex="-1">理解 border-box <a class="header-anchor" href="#理解-border-box" aria-label="Permalink to &quot;理解 border-box&quot;">​</a></h2><p>我们常常会见到 <code>box-sizing: border-box</code> 下 <code>width</code> 和 <code>height</code> 的计算式：</p><ul><li><code>width = content-width + padding-right + padding-left + border-right-width + border-left-width</code></li><li><code>height = content-width + padding-top + padding-bottom + border-top-width + border-bottom-width</code></li></ul><p>但是这无法解释为什么我们设置 <code>width: 0</code> 和 <code>border-width</code> 后还是可以显示 border。</p>',13),h=e('<p>以这个例子来说，<code>width</code> 是 0px，单个 <code>border-width</code> 是 8px，单个 <code>padding</code> 是 8px，那么内容宽度 content-width 应该会算出来是 0px - 8px · 2 - 8px · 2 = -32px。但是 CSS 规范规定了 content-width 最小为 0px，所以取 0px。</p><p>你可以将以上计算式的 <code>width</code> 和 <code>height</code> 理解为元素的理论总宽度和总高度，实际计算时 content-width 最小为 0px，<code>padding</code> 和 <code>border-width</code> 设置的值保留。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/CSS/box-sizing" target="_blank" rel="noreferrer">MDN &gt; References &gt; CSS &gt; box-sizing</a></li></ul>',4);function b(s,x,l,p,g,_){const o=t("VEmbed");return i(),c("div",null,[n,a(o,{src:"https://stackblitz.com/edit/vitejs-vite-cfecs9?embed=1&file=src%2FApp.vue"}),h])}const z=d(r,[["render",b]]);export{u as __pageData,z as default};
